 8→    static class Program
 9→    {
10→        [STAThread]
11→        static void Main()
12→        {
13→            // 전역 예외 핸들러
14→            Application.ThreadException += (s, e) => LogCrash(e.Exception);
15→            AppDomain.CurrentDomain.UnhandledException += (s, e) => LogCrash((Exception)e.ExceptionObject);
16→
17→            // 중복 실행 방지
